1	export type Coordinate = [number, number];
2	
3	const parseCoordinate = (cellString: string): Coordinate => {
4	  const [x, y] = cellString.split(",").map(Number);
5	  return [x, y];
6	};
7	
8	const NEIGHBOR_OFFSETS: Coordinate[] = [
9	  [-1, -1], [-1, 0], [-1, 1],
10	  [0, -1],           [0, 1],
11	  [1, -1],  [1, 0],  [1, 1]
12	];
13	
14	const formatCoordinate = (x: number, y: number): string => {
15	  return `${x},${y}`;
16	};
17	
18	const getNeighborCells = (x: number, y: number): string[] => {
19	  return NEIGHBOR_OFFSETS.map(([dx, dy]) => formatCoordinate(x + dx, y + dy));
20	};
21	
22	const countLiveNeighbors = (cell: string, livingCells: Set<string>): number => {
23	  const [x, y] = parseCoordinate(cell);
24	  const neighborCells = getNeighborCells(x, y);
25	  return neighborCells.reduce((count, neighbor) =>
26	    livingCells.has(neighbor) ? count + 1 : count, 0
27	  );
28	};
29	
30	const shouldCellSurviveOrBeBorn = (isAlive: boolean, liveNeighborCount: number): boolean => {
31	  if (isAlive && (liveNeighborCount === 2 || liveNeighborCount === 3)) {
32	    return true; // Cell survives with 2 or 3 neighbors
33	  }
34	  if (!isAlive && liveNeighborCount === 3) {
35	    return true; // Dead cell becomes alive with exactly 3 neighbors
36	  }
37	  return false;
38	};
39	
40	/**
41	 * Computes the next generation of cells in Conway's Game of Life.
42	 *
43	 * Cells are represented as strings in the format "x,y" where x and y are integers.
44	 *
45	 * Rules applied:
46	 * - Cell with < 2 neighbors dies (underpopulation)
47	 * - Cell with 2-3 neighbors survives
48	 * - Cell with > 3 neighbors dies (overpopulation)
49	 * - Dead cell with exactly 3 neighbors becomes alive (reproduction)
50	 *
51	 * @param cells Set of living cells as coordinate strings "x,y"
52	 * @returns Set of living cells in the next generation
53	 */
54	export function nextGeneration(cells: Set<string>): Set<string> {
55	  const cellsToCheck = new Set<string>();
56	
57	  // Add all living cells and their neighbors to check
58	  for (const cell of cells) {
59	    const [x, y] = parseCoordinate(cell);
60	    cellsToCheck.add(cell);
61	    for (const neighbor of getNeighborCells(x, y)) {
62	      cellsToCheck.add(neighbor);
63	    }
64	  }
65	
66	  const nextGen = new Set<string>();
67	
68	  // Check each cell and determine if it survives or is born
69	  for (const cell of cellsToCheck) {
70	    const isAlive = cells.has(cell);
71	    const liveNeighborCount = countLiveNeighbors(cell, cells);
72	
73	    if (shouldCellSurviveOrBeBorn(isAlive, liveNeighborCount)) {
74	      nextGen.add(cell);
75	    }
76	  }
77	
78	  return nextGen;
79	}
